// Fungsi untuk mendapatkan soal berdasarkan level
export function getQuestionsForLevel(level) {
    const questions = QUESTION_BANK[level];
    if (!questions) return [];
    // Acak urutan soal
    const shuffled = [...questions];
    for (let i = shuffled.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
    }
    return shuffled;
}

// Fungsi untuk mendapatkan reward berdasarkan jenjang
export function getRewardByJenjang(jenjang) {
    const rewards = { sd: 300, smp: 500, smk: 800 };
    return rewards[jenjang] || 300;
}